mapper.select:
SELECT a.*, m.product_title, m.mch_id,m.status, c.id AS attribute_id, c.pid, c.price, c.img, c.num, c.unit, c.attribute FROM lkt_cart AS a LEFT JOIN lkt_product_list AS m ON a.Goods_id = m.id LEFT JOIN lkt_configure AS c ON a.Size_id = c.id
a.Create_time ${create_time_sort},
limit #{pageStart},#{pageEnd}

